/*
 * IoT Device Client - Embedded Implementation
 * Demonstrates device-side management functions:
 * - Telemetry data collection and reporting
 * - Remote configuration handling
 * - Firmware update reception and validation
 * - Secure boot and authentication
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

/* Device Configuration Constants */
#define DEVICE_ID "SENSOR-001"
#define FIRMWARE_VERSION "1.0.0"
#define MAX_TELEMETRY_SIZE 256
#define REPORT_INTERVAL_SEC 60

/* Threshold Values */
#define TEMP_THRESHOLD_HIGH 80
#define TEMP_THRESHOLD_LOW -10
#define BATTERY_THRESHOLD_LOW 20

/* Device Status Structure */
typedef struct {
 char device_id[32];
 char firmware_version[16];
 float temperature;
 uint8_t battery_level;
 int8_t signal_strength;
 uint8_t status; /* 0=offline, 1=active, 2=error */
 uint32_t uptime_seconds;
} DeviceStatus;

/* Telemetry Report Structure */
typedef struct {
 char device_id[32];
 uint32_t timestamp;
 float temperature;
 uint8_t battery;
 int8_t signal;
 uint8_t status_code;
 uint16_t data_size;
} TelemetryReport;

/* Configuration Parameters (Remote Configurable) */
typedef struct {
 uint16_t report_interval;
 uint8_t data_precision;
 uint8_t edge_processing_enabled;
 float temp_calibration_offset;
} DeviceConfig;

/* Global Device State */
static DeviceStatus g_device_status;
static DeviceConfig g_device_config;

/* Function Prototypes */
void initialize_device(void);
void collect_telemetry(DeviceStatus *status);
void process_remote_config(const char *config_data);
int validate_firmware_package(const char *firmware, size_t size);
void apply_firmware_update(const char *firmware_data, size_t size);
void transmit_telemetry(const TelemetryReport *report);
void perform_self_test(void);

/* Initialize device on boot */
void initialize_device(void) {
 printf("[INIT] Starting IoT Device: %s\n", DEVICE_ID);

 // Set initial device status
 strcpy(g_device_status.device_id, DEVICE_ID);
 strcpy(g_device_status.firmware_version, FIRMWARE_VERSION);
 g_device_status.temperature = 25.0f;
 g_device_status.battery_level = 100;
 g_device_status.signal_strength = -50;
 g_device_status.status = 1; // Active
 g_device_status.uptime_seconds = 0;

 // Set default configuration
 g_device_config.report_interval = REPORT_INTERVAL_SEC;
 g_device_config.data_precision = 2;
 g_device_config.edge_processing_enabled = 1;
 g_device_config.temp_calibration_offset = 0.0f;

 printf("[INIT] Device initialized successfully\n");
 printf("[INIT] Firmware Version: %s\n", FIRMWARE_VERSION);
 printf("[INIT] Report Interval: %d seconds\n", g_device_config.report_interval);
}

/* Collect sensor telemetry data */
void collect_telemetry(DeviceStatus *status) {
 // Simulate sensor readings
 // In real implementation, these would read from actual sensors

 status->temperature = 20.0f + (rand() % 60); // Simulated: 20-80 C
 status->battery_level = 100 - (rand() % 30); // Simulated: 70-100%
 status->signal_strength = -30 - (rand() % 70); // Simulated: -30 to -100 dBm
 status->uptime_seconds += g_device_config.report_interval;

 // Apply calibration offset
 status->temperature += g_device_config.temp_calibration_offset;

 printf("[TELEMETRY] Temp: %.1f°C, Battery: %d%%, Signal: %d dBm\n",
 status->temperature, status->battery_level, status->signal_strength);
}

/* Process remote configuration update */
void process_remote_config(const char *config_data) {
 /*
 * Parse configuration JSON (simplified)
 * In production, use proper JSON parser
 */
 printf("[CONFIG] Received remote configuration update\n");

 // Example: "interval:30,precision:1,edge:1,cal_offset:-2.5"
 if (strstr(config_data, "interval:")) {
 int interval = atoi(strstr(config_data, "interval:") + 9);
 if (interval > 0 && interval < 3600) {
 g_device_config.report_interval = interval;
 printf("[CONFIG] Report interval updated to %d seconds\n", interval);
 }
 }

 if (strstr(config_data, "cal_offset:")) {
 float offset = atof(strstr(config_data, "cal_offset:") + 11);
 g_device_config.temp_calibration_offset = offset;
 printf("[CONFIG] Temperature calibration offset: %.1f\n", offset);
 }

 printf("[CONFIG] Configuration applied successfully\n");
}

/* Validate incoming firmware package */
int validate_firmware_package(const char *firmware, size_t size) {
 /*
 * Security: Validate firmware integrity and compatibility
 * In production, use cryptographic signatures and checksums
 */
 printf("[FOTA] Validating firmware package (size: %zu bytes)\n", size);

 // Check minimum size
 if (size < 1024) {
 printf("[FOTA] ERROR: Firmware package too small\n");
 return 0;
 }

 // Check header magic number (simulated)
 // In production: verify digital signature
 if (firmware[0] != 'F' || firmware[1] != 'W') {
 printf("[FOTA] ERROR: Invalid firmware header\n");
 return 0;
 }

 // Simulate version check
 char *version_ptr = strstr(firmware, "VERSION:");
 if (version_ptr) {
 printf("[FOTA] New firmware version detected\n");
 }

 printf("[FOTA] Firmware validation passed\n");
 return 1;
}

/* Apply firmware update */
void apply_firmware_update(const char *firmware_data, size_t size) {
 if (!validate_firmware_package(firmware_data, size)) {
 printf("[FOTA] Update aborted - validation failed\n");
 return;
 }

 printf("[FOTA] Applying firmware update...\n");

 /*
 * In real implementation:
 * 1. Store firmware in temporary partition
 * 2. Verify checksum
 * 3. Switch to new partition
 * 4. Reboot into new firmware
 */

 // Simulate update process
 printf("[FOTA] Writing firmware to flash...\n");
 printf("[FOTA] Verifying checksum...\n");
 printf("[FOTA] Switching to new firmware...\n");

 // Update version string
 strcpy(g_device_status.firmware_version, "1.2.0");

 printf("[FOTA] SUCCESS - Device now running v%s\n", 
 g_device_status.firmware_version);
}

/* Transmit telemetry report to management platform */
void transmit_telemetry(const TelemetryReport *report) {
 /*
 * In real implementation: send via WiFi, Cellular, LoRa, etc.
 * Includes data compression for bandwidth efficiency
 */
 printf("[SEND] Transmitting telemetry to cloud...\n");
 printf(" Device: %s\n", report->device_id);
 printf(" Temp: %.1f°C, Battery: %d%%\n", 
 report->temperature, report->battery);
 printf(" Signal: %d dBm, Status: %d\n",
 report->signal, report->status_code);
 printf("[SEND] Transmission complete (%d bytes)\n", report->data_size);
}

/* Perform device self-diagnostics */
void perform_self_test(void) {
 printf("[DIAG] Running device self-test...\n");

 // Check sensors
 printf("[DIAG] Temperature sensor: OK\n");
 printf("[DIAG] Battery monitor: OK\n");
 printf("[DIAG] Wireless module: OK\n");

 // Check for error conditions
 if (g_device_status.temperature > TEMP_THRESHOLD_HIGH ||
 g_device_status.temperature < TEMP_THRESHOLD_LOW) {
 g_device_status.status = 2; // Error
 printf("[DIAG] WARNING: Temperature out of range!\n");
 }

 if (g_device_status.battery_level < BATTERY_THRESHOLD_LOW) {
 printf("[DIAG] WARNING: Low battery!\n");
 }

 printf("[DIAG] Self-test complete\n");
}

/* Main device control loop */
int main(void) {
 printf("========================================\n");
 printf("IoT Device Client - Management Demo\n");
 printf("========================================\n\n");

 // Initialize device
 initialize_device();

 // Run self-test
 printf("\n");
 perform_self_test();

 // Simulate operation cycle
 printf("\n--- Starting Operation Cycle ---\n");

 // Collect and transmit telemetry
 TelemetryReport report;
 strcpy(report.device_id, g_device_status.device_id);
 report.timestamp = (uint32_t)time(NULL);

 collect_telemetry(&g_device_status);

 report.temperature = g_device_status.temperature;
 report.battery = g_device_status.battery_level;
 report.signal = g_device_status.signal_strength;
 report.status_code = g_device_status.status;
 report.data_size = sizeof(TelemetryReport);

 transmit_telemetry(&report);

 // Simulate receiving remote configuration
 printf("\n");
 process_remote_config("interval:30,precision:1,edge:1,cal_offset:-1.5");

 // Simulate receiving firmware update
 printf("\n");
 char simulated_firmware[] = "FW_VERSION:1.2.0...";
 apply_firmware_update(simulated_firmware, sizeof(simulated_firmware));

 printf("\n========================================\n");
 printf("Device Client Demo Complete\n");
 printf("========================================\n");

 return 0;
}
